func (c *SubstitutionClient) Hooks() []Hook {
	return c.hooks.Substitution
}

// Interceptors returns the client interceptors.
func (c *SubstitutionClient) Interceptors() []Interceptor {
	return c.inters.Substitution
}

func (c *SubstitutionClient) mutate(ctx context.Context, m *SubstitutionMutation) (Value, error) {
	switch m.Op() {
	case OpCreate:
		return (&SubstitutionCreate{config: c.config, hooks: c.Hooks(), mutation: m}).Save(ctx)
	case OpUpdate:
		return (&SubstitutionUpdate{config: c.config, hooks: c.Hooks(), mutation: m}).Save(ctx)
	case OpUpdateOne:
		return (&SubstitutionUpdateOne{config: c.config, hooks: c.Hooks(), mutation: m}).Save(ctx)
	case OpDelete, OpDeleteOne:
		return (&SubstitutionDelete{config: c.config, hooks: c.Hooks(), mutation: m}).Exec(ctx)
	default:
		return nil, fmt.Errorf("ent: unknown Substitution mutation op: %q", m.Op())
	}
}

// hooks and interceptors per client, for fast access.
type (
	hooks struct {
		OptimizationItem, OptimizationResult, Substitution []ent.Hook
	}
	inters struct {
		OptimizationItem, OptimizationResult, Substitution []ent.Interceptor
	}
)
